function downloadCurrentImage(img){if(!img||!img.src)return;let filename=`image_${currentIndex+1}_${Date.now()}`;const urlMatch=img.src.match(/\.([a-z]+)(?:\?|$)/);if(urlMatch){const ext=urlMatch[1];filename+=`.${ext}`;}else{filename+='.jpg';}
fetch(img.src).then(response=>response.blob()).then(blob=>{const blobUrl=window.URL.createObjectURL(blob);const link=document.createElement('a');link.href=blobUrl;link.download=filename;document.body.appendChild(link);link.click();document.body.removeChild(link);window.URL.revokeObjectURL(blobUrl);console.log(`下载图片:${img.src}->${filename}`);}).catch(error=>{console.error('下载失败:',error);const link=document.createElement('a');link.href=img.src;link.download=filename;link.target='_blank';document.body.appendChild(link);link.click();document.body.removeChild(link);notify('下载已开始，如打开新标签页请右键保存图片');});}
