function moveImageToTop(index){const images=getEditorImages();const target=images[index];if(!target)return;const block=getImageBlock(target);const container=window.quill.root;if(block&&container.firstChild){container.insertBefore(block,container.firstChild);syncEditorAfterDomMutation();}}
